void stencil_1d(const int *__restrict__ in, int *__restrict__ out, int length)
{
  const int num_blocks = length / BLOCK_SIZE;

  #pragma omp parallel for schedule(static)
  for (int blockIdx = 0; blockIdx < num_blocks; blockIdx++) {
    int temp[BLOCK_SIZE + 2 * RADIUS];

    for (int threadIdx = 0; threadIdx < BLOCK_SIZE; threadIdx++) {
      int gindex = threadIdx + blockIdx * BLOCK_SIZE;
      int lindex = threadIdx + RADIUS;
      temp[lindex] = in[gindex];
    }

    for (int threadIdx = 0; threadIdx < RADIUS; threadIdx++) {
      int gindex = threadIdx + blockIdx * BLOCK_SIZE;
      int lindex = threadIdx + RADIUS;
      temp[lindex - RADIUS] = (RADIUS > gindex) ? 0 : in[gindex - RADIUS];
      temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
    }

    for (int threadIdx = 0; threadIdx < BLOCK_SIZE; threadIdx++) {
      int gindex = threadIdx + blockIdx * BLOCK_SIZE;
      int lindex = threadIdx + RADIUS;

      int result = 0;
      for (int offset = -RADIUS; RADIUS >= offset; offset++)
        result = result + (temp[lindex + offset]);

      out[gindex] = result;
    }
  }
}

