__attribute__((noinline)) static double benchmark_func_timed(
    T seed, T *g_data, std::size_t total_threads) {
  if (total_threads == 0) return 0.001;

  const std::size_t sample_threads = choose_sample_threads(total_threads);
  const T init = g_data[0];
  std::uint64_t checksum = 0;

  const auto t0 = std::chrono::high_resolution_clock::now();

