  for (long long tid = 0; tid < static_cast<long long>(sample_threads); ++tid) {
    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; ++k) {
      for (unsigned int j = 0; j < granularity; ++j) {
        tmps[j] = init;
        for (unsigned int i = 0; i < compute_iterations; ++i) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      checksum += checksum_value(sum);

      if (equal(sum, conv_int<T>(-1))) {
        g_data[0] = sum;
      }
    }
  }

  const auto t1 = std::chrono::high_resolution_clock::now();
  const double sample_ms =
      std::chrono::duration<double, std::milli>(t1 - t0).count();

  g_sink ^= checksum;

  const double scaled_ms =
      sample_ms * (static_cast<double>(total_threads) / static_cast<double>(sample_threads));
