static float drnd(void)
{
  return ((float) rand() / (float) BIGRND);
}

static float dpn1(void)
{
  return ((drnd() * 2.0f) - 1.0f);
}

float squash(float x)
{
  return (1.0f / (1.0f + expf(-x)));
}

static float *alloc_1d_dbl(int n)
{
  float *new_ptr;

  new_ptr = (float *) malloc((unsigned) (n * sizeof(float)));
  if (new_ptr == NULL) {
    printf("ALLOC_1D_DBL: Couldn't allocate array of floats\n");
    return NULL;
  }
  return new_ptr;
}

float **alloc_2d_dbl(int m, int n)
{
  int i;
  float **new_ptr;

  new_ptr = (float **) malloc((unsigned) (m * sizeof(float *)));
  if (new_ptr == NULL) {
    printf("ALLOC_2D_DBL: Couldn't allocate array of dbl ptrs\n");
    return NULL;
  }

  for (i = 0; i < m; i++) {
    new_ptr[i] = alloc_1d_dbl(n);
  }

  return new_ptr;
}

