struct Node
{
    int starting;
    int no_of_edges;
};

static void Kernel(Node* g_graph_nodes, int* g_graph_edges, unsigned char* g_graph_mask,
                   unsigned char* g_updating_graph_mask, unsigned char* g_graph_visited,
                   int* g_cost, int no_of_nodes)
{
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++)
    {
        if (g_graph_mask[tid])
        {
            g_graph_mask[tid] = 0;
            int next_cost = g_cost[tid] + 1;
            for (int i = g_graph_nodes[tid].starting;
                 i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting);
                 i++)
            {
                int id = g_graph_edges[i];
                if (!g_graph_visited[id])
                {
                    #pragma omp critical(update_neighbor)
                    {
                        g_cost[id] = next_cost;
                        g_updating_graph_mask[id] = 1;
                    }
                }
            }
        }
    }
}

static void Kernel2(unsigned char* g_graph_mask, unsigned char* g_updating_graph_mask,
                    unsigned char* g_graph_visited, unsigned char* g_over, int no_of_nodes)
{
    int over_int = 0;

    #pragma omp parallel for reduction(|:over_int) schedule(static)
    for (int tid = 0; tid < no_of_nodes; tid++)
    {
        if (g_updating_graph_mask[tid])
        {
            g_graph_mask[tid] = 1;
            g_graph_visited[tid] = 1;
            over_int = 1;
            g_updating_graph_mask[tid] = 0;
        }
    }

    *g_over = (unsigned char)over_int;
}

