		compute_window_sums(u->d_in2, u, u->d_in2_sub2);

		for (i = 0; i < common.in2_sqr_elem; i++) {
			temp = u->d_in2[i];
			u->d_in2_sqr[i] = temp * temp;
		}

		compute_window_sums(u->d_in2_sqr, u, u->d_in2_sqr_sub2);

		for (i = 0; i < common.in2_sub2_elem; i++) {
			temp = u->d_in2_sub2[i];
			temp2 = u->d_in2_sqr_sub2[i] - (temp * temp / common.in_elem);
			if (temp2 < 0) {
				temp2 = 0;
			}
			u->d_in2_sqr_sub2[i] = sqrtf(temp2);
		}

		for (i = 0; i < common.in_sqr_elem; i++) {
			temp = d_in[i];
			u->d_in_sqr[i] = temp * temp;
		}

		for (col = 0; col < common.in_cols; col++) {
			sum = 0;
			for (i = 0; i < common.in_rows; i++) {
				sum = sum + d_in[col * common.in_rows + i];
			}
			in_partial_sum[col] = sum;
		}

		for (row = 0; row < common.in_sqr_rows; row++) {
			sum = 0;
			for (i = 0; i < common.in_sqr_cols; i++) {
