static void calculate_temp_cpu_once(float *power,
                                    float *temp_src,
                                    float *temp_dst,
                                    int grid_cols,
                                    int grid_rows,
                                    float Cap,
                                    float Rx,
                                    float Ry,
                                    float Rz,
                                    float step) {
    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

#pragma omp parallel for collapse(2)
    for (int y = 0; y < grid_rows; y++) {
        for (int x = 0; x < grid_cols; x++) {
            int N = (y == 0) ? 0 : y - 1;
            int S = (y == grid_rows - 1) ? grid_rows - 1 : y + 1;
            int W = (x == 0) ? 0 : x - 1;
            int E = (x == grid_cols - 1) ? grid_cols - 1 : x + 1;

            int idx = y * grid_cols + x;
            float center = temp_src[idx];

            temp_dst[idx] = center + step_div_Cap * (
                power[idx] +
                (temp_src[S * grid_cols + x] + temp_src[N * grid_cols + x] - 2.0f * center) * Ry_1 +
                (temp_src[y * grid_cols + E] + temp_src[y * grid_cols + W] - 2.0f * center) * Rx_1 +
                (amb_temp - center) * Rz_1
            );
        }
    }
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows) {
    (void)num_iterations;
