void hotspot_opt1(float *p, float *tIn, float *tOut,
        int nx, int ny, int nz,
        float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    size_t s = sizeof(float) * (size_t)nx * (size_t)ny * (size_t)nz;
    float *tIn_d = tIn;
    float *tOut_d = tOut;

    long long start = get_time();
    for (int iter = 0; iter < numiter; ++iter) {
        #pragma omp parallel for collapse(3) schedule(static)
        for (int z = 0; z < nz; ++z) {
            for (int j = 0; j < ny; ++j) {
                for (int i = 0; i < nx; ++i) {
                    int c = i + j * nx + z * nx * ny;
                    int W = (i == 0) ? c : c - 1;
                    int E = (i == nx - 1) ? c : c + 1;
                    int N = (j == 0) ? c : c - nx;
                    int S = (j == ny - 1) ? c : c + nx;
                    int B = (z == 0) ? c : c - nx * ny;
                    int T = (z == nz - 1) ? c : c + nx * ny;

                    tOut_d[c] = cc * tIn_d[c] + cw * tIn_d[W] + ce * tIn_d[E] + cs * tIn_d[S]
                              + cn * tIn_d[N] + cb * tIn_d[B] + ct * tIn_d[T]
                              + stepDivCap * p[c] + ct * amb_temp;
                }
            }
        }

        {
            float *t = tIn_d;
            tIn_d = tOut_d;
            tOut_d = t;
        }
    }
    long long stop = get_time();
    {
        float time = (float)((stop - start) / (1000.0 * 1000.0));
        printf("Time: %.3f (s)\n", time);
    }

    if (tOut_d != tOut) {
        memcpy(tOut, tOut_d, s);
    }
}

