static void ensureCapacity(Record **records, LatLong **locations, int *capacity, int needed)
{
    Record *newRecords;
    LatLong *newLocations;
    int newCapacity;

    if (*capacity >= needed) return;

    newCapacity = (*capacity == 0) ? 1024 : *capacity;
    while (newCapacity < needed) {
        newCapacity *= 2;
    }

    newRecords = (Record *)realloc(*records, sizeof(Record) * newCapacity);
    newLocations = (LatLong *)realloc(*locations, sizeof(LatLong) * newCapacity);

    if (newRecords == NULL || newLocations == NULL) {
        fprintf(stderr, "Error: out of memory.\n");
        free(newRecords);
        free(newLocations);
        free(*records);
        free(*locations);
        exit(1);
    }

    *records = newRecords;
    *locations = newLocations;
    *capacity = newCapacity;
}

