static void euclid(const LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    int globalId;

    #pragma omp parallel for schedule(static)
    for (globalId = 0; globalId < numRecords; globalId++) {
        float dx = lat - locations[globalId].lat;
        float dy = lng - locations[globalId].lng;
        distances[globalId] = __builtin_sqrtf(dx * dx + dy * dy);
    }
}

