#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[REC_LENGTH];
    float distance;
} Record;

int loadData(char *filename, Record **records, LatLong **locations);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage(void);
int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

static void euclid(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    int globalId;
    #pragma omp parallel for
    for (globalId = 0; globalId < numRecords; globalId++) {
        LatLong *latLong = locations + globalId;
        float *dist = distances + globalId;
        *dist = sqrtf((lat - latLong->lat) * (lat - latLong->lat) +
                      (lng - latLong->lng) * (lng - latLong->lng));
    }
}

int main(int argc, char *argv[])
{
    int i = 0;
    float lat = 0.0f, lng = 0.0f;
    int quiet = 0, timing = 0, platform = 0, device = 0;

    Record *records = NULL;
    LatLong *locations = NULL;
    char filename[100];
    int resultsCount = 10;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    {
        int numRecords = loadData(filename, &records, &locations);
        float *distances;

        if (numRecords < resultsCount) resultsCount = numRecords;

        distances = (float *)malloc(sizeof(float) * (size_t)numRecords);
        if (numRecords > 0 && distances == NULL) {
            fprintf(stderr, "Error: Input too large.\n");
            free(records);
            free(locations);
            exit(1);
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        euclid(locations, distances, numRecords, lat, lng);

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        findLowest(records, distances, numRecords, resultsCount);

        if (!quiet) {
            for (i = 0; resultsCount > i; i++) {
                printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
            }
        }

        free(distances);
        free(records);
        free(locations);
    }

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif

    return 0;
}

int loadData(char *filename, Record **records, LatLong **locations)
{
    FILE *flist, *fp;
    int i = 0;
    char dbname[64];
    int recNum = 0;
    int capacity = OPEN;

    *records = (Record *)malloc(sizeof(Record) * (size_t)capacity);
    *locations = (LatLong *)malloc(sizeof(LatLong) * (size_t)capacity);
    if (*records == NULL || *locations == NULL) {
        fprintf(stderr, "Error allocating memory\n");
        exit(1);
    }

    flist = fopen(filename, "r");
    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if (!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            char substr[6];

            if (fgets(record.recString, 49, fp) == NULL) break;
            fgetc(fp);
            if (feof(fp)) break;

            for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = (float)atof(substr);

            for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = (float)atof(substr);

            if (recNum >= capacity) {
                int newCapacity = capacity + OPEN;
                Record *newRecords = (Record *)realloc(*records, sizeof(Record) * (size_t)newCapacity);
                LatLong *newLocations = (LatLong *)realloc(*locations, sizeof(LatLong) * (size_t)newCapacity);
                if (newRecords == NULL || newLocations == NULL) {
                    fprintf(stderr, "Error allocating memory\n");
                    exit(1);
                }
                *records = newRecords;
                *locations = newLocations;
                capacity = newCapacity;
            }

            (*locations)[recNum] = latLong;
            (*records)[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN)
{
    int i, j;
    float val;
    int minLoc;
    Record *tempRec;
    float tempDist;

    for (i = 0; topN > i; i++) {
        minLoc = i;
        for (j = i; numRecords > j; j++) {
            val = distances[j];
            if (distances[minLoc] > val) minLoc = j;
        }

        tempRec = &records[i];
        records[i] = records[minLoc];
        records[minLoc] = *tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d)
{
    int i;
    char flag;

    if (2 > argc) return 1;
    strncpy(filename, argv[1], 100);

    for (i = 1; argc > i; i++) {
        if ('-' == argv[i][0]) {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    *r = atoi(argv[i]);
                    break;
                case 'l':
                    if ('a' == argv[i][2]) {
                        *lat = (float)atof(argv[i + 1]);
                    } else {
                        *lng = (float)atof(argv[i + 1]);
                    }
                    i++;
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d))
        return 1;
    return 0;
}

