static inline int maximum(int a, int b, int c) {
  int k;
  if (a <= b)
    k = b;
  else
    k = a;

  if (k <= c)
    return c;
  else
    return k;
}

static void process_block(int* referrence, int* matrix_cuda, int cols, int penalty,
                          int b_index_x, int b_index_y) {
  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  int base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

  temp[0][0] = matrix_cuda[base];

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    temp[tx + 1][0] = matrix_cuda[base + cols * (tx + 1)];
    temp[0][tx + 1] = matrix_cuda[base + 1 + tx];
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      ref[ty][tx] = referrence[base + (ty + 1) * cols + (tx + 1)];
    }
  }

  for (int m = 0; m < BLOCK_SIZE; m++) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + 1;
      int t_index_y = m - tx + 1;

      temp[t_index_y][t_index_x] =
          maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                  temp[t_index_y][t_index_x - 1] - penalty,
                  temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + BLOCK_SIZE - m;
      int t_index_y = BLOCK_SIZE - tx;

      temp[t_index_y][t_index_x] =
          maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                  temp[t_index_y][t_index_x - 1] - penalty,
                  temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      matrix_cuda[base + (ty + 1) * cols + (tx + 1)] = temp[ty + 1][tx + 1];
    }
  }
}

static void needle_cuda_shared_1(int* referrence, int* matrix_cuda, int cols,
                                 int penalty, int i, int block_width) {
  (void)block_width;
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    int b_index_x = bx;
    int b_index_y = i - 1 - bx;
    process_block(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
  }
}

static void needle_cuda_shared_2(int* referrence, int* matrix_cuda, int cols,
                                 int penalty, int i, int block_width) {
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    int b_index_x = bx + block_width - i;
    int b_index_y = block_width - bx - 1;
    process_block(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
  }
}

