      }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        matrix_cuda[base + tx + (cols + 1) + ty * cols] = temp[ty + 1][tx + 1];
      }
    }
  }
}

static void needle_cuda_shared_2(int *referrence,
                                 int *matrix_cuda,
                                 int cols,
                                 int penalty,
                                 int i,
                                 int block_width) {
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    int b_index_x = bx + block_width - i;
    int b_index_y = block_width - bx - 1;
    int base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref[ty][tx] = referrence[base + tx + (cols + 1) + cols * ty];
      }
    }

    temp[0][0] = matrix_cuda[base];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      temp[tx + 1][0] = matrix_cuda[base + cols + cols * tx];
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      temp[0][tx + 1] = matrix_cuda[base + tx + 1];
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
      for (int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;
        temp[t_index_y][t_index_x] =
            maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                    temp[t_index_y][t_index_x - 1] - penalty,
                    temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
      for (int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;
        temp[t_index_y][t_index_x] =
            maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                    temp[t_index_y][t_index_x - 1] - penalty,
                    temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        matrix_cuda[base + tx + (cols + 1) + ty * cols] = temp[ty + 1][tx + 1];
      }
    }
  }
}

