  int *matrix_cuda, *referrence_cuda;
  int size;

  if (argc == 3) {
    max_rows = atoi(argv[1]);
    max_cols = atoi(argv[1]);
    penalty = atoi(argv[2]);
  } else {
    usage(argc, argv);
  }

  if (atoi(argv[1]) % 16 != 0) {
    fprintf(stderr, "The dimension values must be a multiple of 16\n");
    exit(1);
  }

  max_rows += 1;
  max_cols = max_cols + 1;
  referrence = (int *)malloc(max_rows * max_cols * sizeof(int));
  input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
  output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

  if (!input_itemsets)
    fprintf(stderr, "error: can not allocate memory");

  srand(7);

  for (int i = 0; i < max_cols; i++) {
    for (int j = 0; max_rows > j; j++) {
      input_itemsets[i * max_cols + j] = 0;
    }
  }

  printf("Start Needleman-Wunsch\n");

  for (int i = 1; max_rows > i; i++) {
    input_itemsets[i * max_cols] = rand() % 10 + 1;
  }
  for (int j = 1; max_cols > j; j++) {
    input_itemsets[j] = rand() % 10 + 1;
  }

  for (int i = 1; i < max_cols; i++) {
    for (int j = 1; max_rows > j; j++) {
      referrence[i * max_cols + j] =
          blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
    }
  }

  for (int i = 1; i < max_rows; i++)
    input_itemsets[i * max_cols] = -i * penalty;
  for (int j = 1; max_cols > j; j++)
    input_itemsets[j] = -j * penalty;

  size = max_cols * max_rows;
  referrence_cuda = (int *)malloc(sizeof(int) * size);
  matrix_cuda = (int *)malloc(sizeof(int) * size);

  memcpy(referrence_cuda, referrence, sizeof(int) * size);
  memcpy(matrix_cuda, input_itemsets, sizeof(int) * size);

  int block_width = (max_cols - 1) / BLOCK_SIZE;

#ifdef TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

  printf("Processing top-left matrix\n");

  for (int i = 1; block_width >= i; i++) {
    needle_cuda_shared_1(referrence_cuda, matrix_cuda, max_cols, penalty, i, block_width);
  }
  printf("Processing bottom-right matrix\n");

  for (int i = block_width - 1; 1 <= i; i--) {
    needle_cuda_shared_2(referrence_cuda, matrix_cuda, max_cols, penalty, i, block_width);
  }

#ifdef TIMING
  gettimeofday(&tv_kernel_end, NULL);
  tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
  kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  memcpy(output_itemsets, matrix_cuda, sizeof(int) * size);

#ifdef TRACEBACK
  FILE *fpo = fopen("result.txt", "w");
  fprintf(fpo, "print traceback value GPU:\n");

  for (int i = max_rows - 2, j = max_rows - 2; i >= 0, j >= 0;) {
    int nw, n, w, traceback;
    if (i == max_rows - 2 && j == max_rows - 2)
      fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
    if (i == 0 && j == 0)
      break;
    if (i > 0 && j > 0) {
      nw = output_itemsets[(i - 1) * max_cols + j - 1];
      w = output_itemsets[i * max_cols + j - 1];
      n = output_itemsets[(i - 1) * max_cols + j];
    } else if (i == 0) {
      nw = n = LIMIT;
      w = output_itemsets[i * max_cols + j - 1];
    } else if (j == 0) {
      nw = w = LIMIT;
      n = output_itemsets[(i - 1) * max_cols + j];
    } else {
    }

    int new_nw, new_w, new_n;
    new_nw = nw + referrence[i * max_cols + j];
    new_w = w - penalty;
    new_n = n - penalty;

    traceback = maximum(new_nw, new_w, new_n);
    if (traceback == new_nw)
      traceback = nw;
    if (traceback == new_w)
      traceback = w;
    if (traceback == new_n)
      traceback = n;

    fprintf(fpo, "%d ", traceback);

    if (traceback == nw) {
      i--;
      j--;
      continue;
    } else if (traceback == w) {
      j--;
      continue;
    } else if (traceback == n) {
      i--;
      continue;
    } else
      ;
  }

  fclose(fpo);
#endif

  free(referrence_cuda);
  free(matrix_cuda);

  free(referrence);
  free(input_itemsets);
  free(output_itemsets);

#ifdef TIMING
  printf("Exec: %f\n", kernel_time);
#endif
}

