double calcLikelihoodSum(unsigned char *I, int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; numOnes > x; x++) {
        likelihoodSum = likelihoodSum +
                        ((pow((double)(I[ind[index * numOnes + x]] - 100), 2) -
                          pow((double)(I[ind[index * numOnes + x]] - 228), 2)) /
                         50.0);
    }
    return likelihoodSum;
}

void cdfCalc(double *CDF, double *weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; Nparticles > x; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

double d_randu(int *seed, int index) {
    long long num = ((long long)A) * seed[index] + C;
    seed[index] = (int)(num % M);
    return fabs(seed[index] / ((double)M));
}

double randu(int *seed, int index) {
    long long num = ((long long)A) * seed[index] + C;
    seed[index] = (int)(num % M);
    return fabs(seed[index] / ((double)M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double test_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double d_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double updateWeights(double *weights, double *likelihood, int Nparticles) {
    int x;
    double sum = 0;
    for (x = 0; Nparticles > x; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum = sum + weights[x];
    }
    return sum;
}

int findIndexBin(double *CDF, int beginIndex, int endIndex, double value) {
    if (beginIndex > endIndex)
        return -1;
    int middleIndex;
    while (beginIndex < endIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (value <= CDF[middleIndex]) {
            if (0 == middleIndex)
                return middleIndex;
            else if (value > CDF[middleIndex - 1])
                return middleIndex;
            else if (value == CDF[middleIndex - 1]) {
                while (value == CDF[middleIndex] && 0 <= middleIndex)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (value < CDF[middleIndex])
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

double dev_round_double(double value) {
    int newValue = (int)(value);
    if (.5f > value - newValue)
        return newValue;
    else
        return newValue++;
}

void find_index_kernel(double *arrayX, double *arrayY, double *CDF, double *u,
                       double *xj, double *yj, double *weights, int Nparticles) {
    (void)weights;
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (u[i] <= CDF[x]) {
                index = x;
                break;
            }
        }
        if (-1 == index) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void normalize_weights_kernel(double *weights, int Nparticles, double *partial_sums,
                              double *CDF, double *u, int *seed) {
    double sumWeights = partial_sums[0];

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1 / ((double)(Nparticles))) * d_randu(seed, 0);

    {
        double u1 = u[0];
        #pragma omp parallel for
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double)(Nparticles));
        }
    }
}

void sum_kernel(double *partial_sums, int Nparticles) {
    (void)Nparticles;
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
    double sum = 0.0;
    for (int x = 0; num_blocks > x; x++) {
        sum = sum + partial_sums[x];
    }
    partial_sums[0] = sum;
}

void likelihood_kernel(double *arrayX, double *arrayY, double *xj, double *yj,
                       double *CDF, int *ind, int *objxy, double *likelihood,
                       unsigned char *I, double *u, double *weights,
                       int Nparticles, int countOnes, int max_size, int k,
                       int IszY, int Nfr, int *seed, double *partial_sums) {
    (void)CDF;
    (void)u;

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((double)(Nparticles));

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);

        for (int y = 0; countOnes > y; y++) {
            int indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (max_size <= ind[i * countOnes + y])
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    #pragma omp parallel for
    for (int block = 0; block < num_blocks; block++) {
        int start = block * threads_per_block;
        int end = start + threads_per_block;
        if (end > Nparticles)
            end = Nparticles;
        double sum = 0.0;
        for (int i = start; i < end; i++) {
            sum += weights[i];
        }
        partial_sums[block] = sum;
    }
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (.5 > value - newValue)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D,
           int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    #pragma omp parallel for collapse(3) private(x, y, z)
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                if (testValue == array3D[x * *dimY * *dimZ + y * *dimZ + z])
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = (unsigned char)newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] +
                    (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    #pragma omp parallel for collapse(2) private(x, y)
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) +
                                   pow((double)(y - radius + 1), 2));
            if (radius > distance)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ,
                   int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX)
        startX++;
    int startY = posY - error;
    while (0 > startY)
        startY++;
    int endX = posX + error;
    while (dimX < endX)
        endX--;
    int endY = posY + error;
    while (dimY < endY)
        endY--;
    int x, y;
    for (x = startX; endX > x; x++) {
        for (y = startY; endY > y; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) +
                                   pow((double)(y - posY), 2));
            if (error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ,
                   int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; dimZ > z; z++) {
        for (x = 0; dimX > x; x++) {
            for (y = 0; dimY > y; y++) {
                if (1 == matrix[x * dimY * dimZ + y * dimZ + z]) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; Nfr > k; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (max_size <= pos)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));
    if (newMatrix == NULL) {
        exit(1);
    }
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    #pragma omp parallel for collapse(3) private(x, y, k)
    for (x = 0; IszX > x; x++) {
        for (y = 0; IszY > y; y++) {
            for (k = 0; Nfr > k; k++) {
                I[x * IszY * Nfr + y * Nfr + k] =
                    newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; lengthCDF > x; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (-1 == index) {
        return lengthCDF - 1;
    }
    return index;
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc(diameter * diameter * sizeof(int));
    if (disk == NULL) {
        exit(1);
    }
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; diameter > x; x++) {
