static void srad_omp_1(
	float *E_C,
	float *W_C,
	float *N_C,
	float *S_C,
	float *J,
	float *C,
	int cols,
	int rows,
	float q0sqr)
{
#pragma omp parallel for collapse(2) schedule(static)
	for (int i = 0; i < rows; i++) {
		for (int j = 0; j < cols; j++) {
			int k = i * cols + j;
			int iN = (i == 0) ? 0 : (i - 1);
			int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
			int jW = (j == 0) ? 0 : (j - 1);
			int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

			float jc = J[k];
			float n = J[iN * cols + j] - jc;
			float s = J[iS * cols + j] - jc;
			float w = J[i * cols + jW] - jc;
			float e = J[i * cols + jE] - jc;

			float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
			float l = (n + s + w + e) / jc;

			float num = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
			float den = 1.0f + (0.25f * l);
			float qsqr = num / (den * den);

			den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
			float c = 1.0f / (1.0f + den);

			if (c < 0.0f) {
				c = 0.0f;
			} else if (c > 1.0f) {
				c = 1.0f;
			}

			C[k] = c;
			E_C[k] = e;
			W_C[k] = w;
			S_C[k] = s;
			N_C[k] = n;
		}
	}
}

static void srad_omp_2(
	float *E_C,
	float *W_C,
	float *N_C,
	float *S_C,
	float *J,
	float *C,
	int cols,
	int rows,
	float lambda,
	float q0sqr)
{
