using namespace std;

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

class PStream {
public:
  virtual size_t read(float* dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_) {
    n = n_;
  }
  size_t read(float* dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
  ~SimStream() {
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float* dest, int dim, int num) {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE
#define CACHE_LINE 512

static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search = 0.0;
double time_speedy = 0.0;
double time_select_feasible = 0.0;
double time_gain = 0.0;
double time_shuffle = 0.0;
double time_gain_dist = 0.0;
double time_gain_init = 0.0;
#endif

static float *work_mem_h = NULL;
static float *coord_h = NULL;
static float *work_mem_d = NULL;
static float *coord_d = NULL;
static int   *center_table_d = NULL;
static bool  *switch_membership_d = NULL;
static Point *p = NULL;
static int iter = 0;

static long coord_h_capacity = 0;
static long coord_d_capacity = 0;
static long center_table_capacity = 0;
static long switch_membership_capacity = 0;
static long point_capacity = 0;

void inttofile(int data, char *filename) {
  FILE *fp = fopen(filename, "w");
  fprintf(fp, "%d ", data);
  fclose(fp);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j) {
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return 1;
  if (a < b) return -1;
  return 0;
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
  return result;
}

static inline float d_dist(int p1, int p2, int num, int dim, float *coord_arr) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord_arr[(long)i * num + p1] - coord_arr[(long)i * num + p2];
    retval += tmp * tmp;
  }
  return retval;
}

static void kernel_compute_cost(int num, int dim, long x, Point *p_arr, int K, int stride,
                                float *coord_arr, float *work_mem_arr, int *center_table_arr,
                                bool *switch_membership_arr) {
#pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_arr[(long)tid * stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord_arr) * p_arr[tid].weight;
    if (p_arr[tid].cost > x_cost) {
      switch_membership_arr[tid] = 1;
      lower[K] += x_cost - p_arr[tid].cost;
    } else {
      lower[center_table_arr[p_arr[tid].assign]] += p_arr[tid].cost - x_cost;
    }
  }
}

void allocDevMem(int num, int dim) {
  long coord_need = (long)num * dim;
  if (center_table_capacity < num) {
    free(center_table_d);
    center_table_d = (int*)malloc((size_t)num * sizeof(int));
    center_table_capacity = num;
  }
  if (switch_membership_capacity < num) {
    free(switch_membership_d);
    switch_membership_d = (bool*)malloc((size_t)num * sizeof(bool));
    switch_membership_capacity = num;
  }
  if (point_capacity < num) {
    free(p);
    p = (Point*)malloc((size_t)num * sizeof(Point));
    point_capacity = num;
  }
  if (coord_d_capacity < coord_need) {
    free(coord_d);
    coord_d = (float*)malloc((size_t)coord_need * sizeof(float));
    coord_d_capacity = coord_need;
  }
}

void allocHostMem(int num, int dim) {
  long coord_need = (long)num * dim;
  if (coord_h_capacity < coord_need) {
    free(coord_h);
    coord_h = (float*)malloc((size_t)coord_need * sizeof(float));
    coord_h_capacity = coord_need;
  }
}

void freeDevMem() {
  free(center_table_d);
  free(switch_membership_d);
  free(p);
  free(coord_d);
  center_table_d = NULL;
  switch_membership_d = NULL;
  p = NULL;
  coord_d = NULL;
  center_table_capacity = 0;
  switch_membership_capacity = 0;
  point_capacity = 0;
  coord_d_capacity = 0;
}

void freeHostMem() {
  free(coord_h);
  coord_h = NULL;
  coord_h_capacity = 0;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center_arr,
            int *center_table_arr, bool *switch_membership_arr, bool isCoordChangedFlag,
            double *serial_t_arr, double *cpu_to_gpu_t_arr, double *gpu_to_cpu_t_arr,
            double *alloc_t_arr, double *kernel_t_arr, double *free_t_arr) {
#ifdef PROFILE
  double t_gain_1 = gettime();
#endif

  double t1, t2;

  int stride = (int)(*numcenters + 1);
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  int nThread = num;

  t1 = gettime();
  work_mem_h = (float*)malloc((size_t)stride * (nThread + 1) * sizeof(float));
  if (iter == 0) {
    allocHostMem(num, dim);
  } else {
    allocHostMem(num, dim);
  }

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }

  if (isCoordChangedFlag || iter == 0) {
    for (int i = 0; i < dim; i++) {
      for (int j = 0; j < num; j++) {
        coord_h[(long)num * i + j] = points->p[j].coord[i];
      }
    }
  }
  t2 = gettime();
  *serial_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  work_mem_d = (float*)malloc((size_t)stride * (nThread + 1) * sizeof(float));
  allocDevMem(num, dim);
  t2 = gettime();
  *alloc_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  if (isCoordChangedFlag || iter == 0) {
    memcpy(coord_d, coord_h, (size_t)num * dim * sizeof(float));
  }
  memcpy(center_table_d, center_table_arr, (size_t)num * sizeof(int));
  memcpy(p, points->p, (size_t)num * sizeof(Point));
  memset((void*)switch_membership_d, 0, (size_t)num * sizeof(bool));
  memset((void*)work_mem_d, 0, (size_t)stride * (nThread + 1) * sizeof(float));
  t2 = gettime();
  *cpu_to_gpu_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  kernel_compute_cost(num, dim, x, p, K, stride, coord_d, work_mem_d, center_table_d, switch_membership_d);
  t2 = gettime();
  *kernel_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  memcpy(work_mem_h, work_mem_d, (size_t)stride * (nThread + 1) * sizeof(float));
  memcpy(switch_membership_arr, switch_membership_d, (size_t)num * sizeof(bool));
  t2 = gettime();
  *gpu_to_cpu_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[(long)stride * nThread];

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low = low + work_mem_h[(long)j * stride + center_table_arr[i]];
      }
      gl_lower[center_table_arr[i]] = low;

      if (0 < low) {
        ++number_of_centers_to_close;
        work_mem_h[(long)i * stride + K] -= low;
      }
    }
    gl_cost_of_opening_x = gl_cost_of_opening_x + work_mem_h[(long)i * stride + K];
  }

  if (0 > gl_cost_of_opening_x) {
    for (int i = 0; i < num; i++) {
      bool close_center = 0 < gl_lower[center_table_arr[points->p[i].assign]];
      if (switch_membership_arr[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && 0 < gl_lower[center_table_arr[i]]) {
        is_center_arr[i] = false;
      }
    }

    if (0 <= x && num > x) {
      is_center_arr[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  work_mem_h = NULL;
  t2 = gettime();
  *serial_t_arr += (t2 - t1) * 1000.0;

  t1 = gettime();
  free(work_mem_d);
  work_mem_d = NULL;
  t2 = gettime();
  *free_t_arr += (t2 - t1) * 1000.0;

  iter++;

#ifdef PROFILE
  double t_gain_2 = gettime();
  time_gain += t_gain_2 - t_gain_1;
#endif

  return -gl_cost_of_opening_x;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  long numberOfPoints = points->num;
  int dim = points->dim;

#pragma omp parallel for schedule(static)
  for (long k = 0; k < numberOfPoints; k++) {
    float distance = dist(points->p[k], points->p[0], dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < numberOfPoints; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < numberOfPoints; k++) {
        float distance = dist(points->p[i], points->p[k], dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
#pragma omp parallel for reduction(+:totalcost) schedule(static)
  for (long k = 0; k < numberOfPoints; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc((size_t)numfeasible * sizeof(int));

  float* accumweight;
  float totalweight;
  long k1 = 0;
  long k2 = numfeasible;
  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < (int)k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float*)malloc((size_t)points->num * sizeof(float));
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < (int)k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter_count, float e) {
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter_count; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership, isCoordChanged,
                      &serial_t, &cpu_to_gpu_t, &gpu_to_cpu_t, &alloc_t, &kernel_t, &free_t);
    }

    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n",
            *k, cost, cost - z * (*k));
#endif
    (void)numberOfPoints;
  }
  return cost;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;
  long k;
  int *feasible = NULL;
  int numfeasible = 0;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

#pragma omp parallel for reduction(+:hiz) schedule(static)
  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], (int)ptDimension) * points->p[kk].weight;
  }

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
#pragma omp parallel for schedule(static)
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = points->num;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int j = 0; j < points->num; j++) {
    is_center[j] = false;
  }
  for (int j = 0; j < points->num; j++) {
    is_center[points->p[j].assign] = true;
  }

  while (1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
    (void)lastcost;
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;
  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  pkmedian(points, kmin, kmax, kfinal);
#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc((size_t)centers->num, sizeof(int));
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned int)centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc((size_t)chunksize * dim * sizeof(float));
  float* centerBlock = (float*)malloc((size_t)centersize * dim * sizeof(float));
  long* centerIDs = (long*)malloc((size_t)centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[(long)i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[(long)i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, (int)chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool*)malloc((size_t)points.num * sizeof(bool));
    is_center = (bool*)calloc((size_t)points.num, sizeof(bool));
    center_table = (int*)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");

    contcenters(&points);
    isCoordChanged = true;

    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += (long)numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (bool*)malloc((size_t)centers.num * sizeof(bool));
  is_center = (bool*)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int*)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

