static unsigned long verification_value(Input input, SimulationData data, double E, int mat)
{
	double macro_xs[4] = {0.0, 0.0, 0.0, 0.0};
	calculate_macro_xs(macro_xs, mat, E, input, data);

	double max = -DBL_MAX;
	int max_idx = 0;
	for(int x = 0; x < 4; x++)
	{
		if(macro_xs[x] > max)
		{
			max = macro_xs[x];
			max_idx = x;
		}
	}

	return (unsigned long)(max_idx + 1);
}

static int sample_compare_mat_energy(const void *a, const void *b)
{
	const Sample *sa = (const Sample *) a;
	const Sample *sb = (const Sample *) b;

	if(sa->mat < sb->mat) return -1;
	if(sa->mat > sb->mat) return 1;
	if(sa->E < sb->E) return -1;
	if(sa->E > sb->E) return 1;
	return 0;
}

void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result)
{
	printf("Running baseline event-based simulation on device...\n");

	unsigned long verification_scalar = 0;

	#pragma omp parallel for reduction(+:verification_scalar) schedule(static)
	for(int i = 0; i < input.lookups; i++)
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t) i);

		double E = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		verification_scalar += verification_value(input, data, E, mat);
	}

	printf("Reducing verification results...\n");

	*vhash_result = verification_scalar;
