void run_history_based_simulation(Input input, SimulationData data, unsigned long * vhash_result)
{
	unsigned long verification_scalar = 0;

	#pragma omp parallel for reduction(+:verification_scalar) schedule(static)
	for(int p = 0; p < input.particles; p++)
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t) input.lookups * (uint64_t) p);

		for(int i = 0; i < input.lookups; i++)
