double LCG_random_double(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL;
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return (double) (*seed) / (double) m;
}

uint64_t LCG_random_int(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL;
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return *seed;
}

uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
	const uint64_t m = 9223372036854775808ULL;
	uint64_t a = 2806196910506780709ULL;
	uint64_t c = 1ULL;

	n = n % m;

	uint64_t a_new = 1ULL;
	uint64_t c_new = 0ULL;

	while(n > 0)
	{
		if(n & 1ULL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1ULL);
		a *= a;

		n >>= 1ULL;
	}

	return (a_new * seed + c_new) % m;
}

RSComplex c_add(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r + B.r;
	C.i = A.i + B.i;
	return C;
}

RSComplex c_sub(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r - B.r;
	C.i = A.i - B.i;
	return C;
}

RSComplex c_mul(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	C.r = (a * c) - (b * d);
	C.i = (a * d) + (b * c);
	return C;
}

RSComplex c_div(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	double denom = c * c + d * d;
	C.r = ((a * c) + (b * d)) / denom;
	C.i = ((b * c) - (a * d)) / denom;
	return C;
}

double c_abs(RSComplex A)
{
	return sqrt(A.r * A.r + A.i * A.i);
}

RSComplex fast_cexp(RSComplex z)
{
	double x = z.r;
	double y = z.i;

	double t1 = fast_exp(x);
	double t2 = cos(y);
	double t3 = sin(y);
	RSComplex t4 = {t2, t3};
	RSComplex t5 = {t1, 0.0};
	RSComplex result = c_mul(t5, t4);
	return result;
}

void run_event_based_simulation_optimization_1(Input in, SimulationData SD, unsigned long * vhash_result)
