void calculate_macro_xs( double * macro_xs, int mat, double E, Input input, SimulationData data )
{
	for( int i = 0; i < 4; i++ )
		macro_xs[i] = 0;

	for( int i = 0; i < data.num_nucs[mat]; i++ )
	{
		double micro_xs[4];
		int nuc = data.mats[mat * data.max_num_nucs + i];

		if( input.doppler == 1 )
			calculate_micro_xs_doppler(micro_xs, nuc, E, input, data);
		else
			calculate_micro_xs(micro_xs, nuc, E, input, data);

		for( int j = 0; j < 4; j++ )
			macro_xs[j] += micro_xs[j] * data.concs[mat * data.max_num_nucs + i];
	}
}

void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result )
{
	printf("Running baseline event-based simulation on device...\n");

	unsigned long * verification = (unsigned long *) malloc((size_t) input.lookups * sizeof(unsigned long));

	#pragma omp parallel for schedule(static)
	for( int i = 0; i < input.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t) i);

		double E = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		double macro_xs[4] = {0,0,0,0};
		calculate_macro_xs(macro_xs, mat, E, input, data);

		double max = -DBL_MAX;
		int max_idx = 0;
		for( int x = 0; x < 4; x++ )
		{
			if( max < macro_xs[x] )
			{
				max = macro_xs[x];
				max_idx = x;
			}
		}
		verification[i] = (unsigned long) (max_idx + 1);
	}

	printf("Reducing verification results...\n");

	unsigned long verification_scalar = 0;
	#pragma omp parallel for reduction(+:verification_scalar) schedule(static)
	for( int i = 0; i < input.lookups; i++ )
		verification_scalar += verification[i];

	*vhash_result = verification_scalar;

	free(verification);
}

void run_event_based_simulation_optimization_1(Input in, SimulationData SD, unsigned long * vhash_result)
{
	const char * optimization_name = "Optimization 1 - Material & Energy Sorts + Material-specific Kernels";

	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	printf("Allocating additional device data required by kernel...\n");
	size_t sz;
	size_t total_sz = 0;

	sz = (size_t) in.lookups * sizeof(double);
	SD.p_energy_samples = (double *) malloc(sz);
	total_sz += sz;
	SD.length_p_energy_samples = in.lookups;

	sz = (size_t) in.lookups * sizeof(int);
	SD.mat_samples = (int *) malloc(sz);
	total_sz += sz;
	SD.length_mat_samples = in.lookups;

	printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz / 1024.0 / 1024.0);

	printf("Beginning optimized simulation...\n");

	#pragma omp parallel for schedule(static)
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t) i);

		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		SD.p_energy_samples[i] = p_energy;
		SD.mat_samples[i] = mat;
	}

	int n_lookups_per_material[12];
	for( int m = 0; m < 12; m++ )
		n_lookups_per_material[m] = 0;

	for( int i = 0; i < in.lookups; i++ )
		n_lookups_per_material[SD.mat_samples[i]]++;

	SamplePair * pairs = (SamplePair *) malloc((size_t) in.lookups * sizeof(SamplePair));
	for( int i = 0; i < in.lookups; i++ )
	{
		pairs[i].mat = SD.mat_samples[i];
		pairs[i].energy = SD.p_energy_samples[i];
	}

	qsort(pairs, (size_t) in.lookups, sizeof(SamplePair), compare_sample_pair);

	for( int i = 0; i < in.lookups; i++ )
	{
		SD.mat_samples[i] = pairs[i].mat;
