	for( int i = 0; i < in.n_isotopes; i++ )
		qsort(&SD.nuclide_grid[i * in.n_gridpoints], (size_t)in.n_gridpoints, sizeof(NuclideGridPoint), NGP_compare);

	if( in.grid_type == NUCLIDE )
